package com.example.documentviewer; // Replace with your actual package name

import android.app.Activity;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.Build;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.util.Log;
import android.view.View;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;

import java.io.FileNotFoundException;
import java.io.IOException;

public class DocumentViewerActivity extends Activity {

    private static final String TAG = "DocumentViewerActivity";
    private ImageView documentImageView;
    private TextView errorTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        documentImageView = findViewById(R.id.documentImageView);
        errorTextView = findViewById(R.id.errorTextView);

        // Handle the initial intent when the activity is created
        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        // Set the new intent as the activity's current intent, important for standard launchMode
        setIntent(intent);
        // Handle the new intent
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent == null || !Intent.ACTION_VIEW.equals(intent.getAction())) {
            showError("No document to view or unsupported action.");
            return;
        }

        Uri uri = intent.getData();
        String mimeType = intent.getType();

        if (uri == null) {
            showError("Document URI is null.");
            return;
        }

        Log.d(TAG, "Received URI: " + uri.toString());
        Log.d(TAG, "Received MIME Type: " + mimeType);

        // Hide previous error/content
        errorTextView.setVisibility(View.GONE);
        documentImageView.setVisibility(View.GONE);

        if (mimeType != null) {
            if (mimeType.startsWith("image/")) {
                displayImage(uri);
            } else if ("application/pdf".equals(mimeType)) {
                displayPdf(uri);
            } else {
                showError("Unsupported document type: " + mimeType);
            }
        } else {
            // If MIME type is null, try to infer from URI path
            String path = uri.getPath();
            if (path != null) {
                if (path.toLowerCase().endsWith(".pdf")) {
                    displayPdf(uri);
                } else if (path.toLowerCase().endsWith(".jpg") ||
                           path.toLowerCase().endsWith(".jpeg") ||
                           path.toLowerCase().endsWith(".png") ||
                           path.toLowerCase().endsWith(".gif") ||
                           path.toLowerCase().endsWith(".bmp") ||
                           path.toLowerCase().endsWith(".webp")) {
                    displayImage(uri);
                } else {
                    showError("Could not determine document type from URI: " + uri.toString());
                }
            } else {
                showError("Cannot determine document type from URI.");
            }
        }
    }

    private void displayImage(Uri imageUri) {
        try {
            documentImageView.setImageURI(imageUri);
            documentImageView.setVisibility(View.VISIBLE);
        } catch (SecurityException e) {
            Log.e(TAG, "Security error displaying image: " + imageUri, e);
            showError("Permission denied to access image. Ensure app has read permissions.");
        } catch (Exception e) {
            Log.e(TAG, "Error displaying image: " + imageUri, e);
            showError("Failed to display image.");
        }
    }

    private void displayPdf(Uri pdfUri) {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.LOLLIPOP) {
            showError("PDF viewing requires Android 5.0 (API 21) or higher.");
            return;
        }

        try (ParcelFileDescriptor pfd = getContentResolver().openFileDescriptor(pdfUri, "r")) {
            if (pfd == null) {
                showError("Failed to open PDF document: " + pdfUri);
                return;
            }

            // PdfRenderer takes ownership of the ParcelFileDescriptor and closes it when PdfRenderer.close() is called
            PdfRenderer renderer = new PdfRenderer(pfd);
            try {
                if (renderer.getPageCount() == 0) {
                    showError("PDF document is empty.");
                    return;
                }

                // For simplicity, we display only the first page.
                // A full viewer would implement scrolling, zooming, multi-page display.
                PdfRenderer.Page page = renderer.openPage(0);
                try {
                    // Create a bitmap to render the page onto
                    Bitmap bitmap = Bitmap.createBitmap(page.getWidth(), page.getHeight(), Bitmap.Config.ARGB_8888);
                    // Render the page onto the bitmap
                    page.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY);

                    documentImageView.setImageBitmap(bitmap);
                    documentImageView.setVisibility(View.VISIBLE);
                } finally {
                    page.close(); // Close the page
                }
            } finally {
                renderer.close(); // Close the renderer (which also closes the PFD)
            }
        } catch (FileNotFoundException e) {
            Log.e(TAG, "PDF file not found: " + pdfUri, e);
            showError("PDF file not found.");
        } catch (IOException e) {
            Log.e(TAG, "Error opening or rendering PDF: " + pdfUri, e);
            showError("Failed to open or render PDF.");
        } catch (SecurityException e) {
            Log.e(TAG, "Security error opening PDF: " + pdfUri, e);
            showError("Permission denied to open PDF. Ensure app has read permissions.");
        } catch (Exception e) { // Catch any other unexpected exceptions
            Log.e(TAG, "An unexpected error occurred while displaying PDF: " + pdfUri, e);
            showError("An unexpected error occurred.");
        }
    }

    private void showError(String message) {
        errorTextView.setText(message);
        errorTextView.setVisibility(View.VISIBLE);
        documentImageView.setVisibility(View.GONE);
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
    }
}

